<?= $this->include('template/header') ?><h1>Data Artikel AJAX</h1><table class="table" id="artikelTable"><thead><tr><th>ID</th><th>Judul</th><th>Status</th><th>Aksi</th></tr></thead><tbody></tbody></table><script src="https://code.jquery.com/jquery-3.6.0.min.js"></script><script>$(document).ready(function(){function loadData(){ $('#artikelTable tbody').html('<tr><td colspan="4">Loading data...</td></tr>'); $.ajax({url:'<?= base_url('ajax/getData') ?>',method:'GET',dataType:'json',success:function(data){let html='';data.forEach(function(row){html+=`<tr><td>${row.id}</td><td>${row.judul}</td><td>${row.status==1?'Publish':'Draft'}</td><td><a href="<?= base_url('admin/artikel/edit/') ?>${row.id}" class="btn">Edit</a> <a href="#" class="btn btn-danger btn-delete" data-id="${row.id}">Delete</a></td></tr>`});$('#artikelTable tbody').html(html)}})}loadData();$(document).on('click','.btn-delete',function(e){e.preventDefault();let id=$(this).data('id');if(confirm('Apakah Anda yakin ingin menghapus artikel ini?')){$.ajax({url:'<?= base_url('ajax/delete/') ?>'+id,method:'DELETE',success:function(){loadData();},error:function(){alert('Error deleting article');}})}})});</script><?= $this->include('template/footer') ?>
